async function run() {
  var fahh = new Audio("data:audio/mp3;base64,")

  const model = await roboflow.auth({ publishable_key: "rf_LSdumIOTyfdnblA3TprEXVpMvUs1" })
      .load({ model: "squirrel-kgcpd", version: 1 });

    const video = document.getElementById('videoElement');


    await new Promise((resolve) => {
      if (video.readyState >= 2) {
        resolve(); // already ready
      } else {
        video.addEventListener('loadeddata', resolve);
      }
    });

    const predictions = await model.detect(video);
    console.log("weeee")
    console.log(predictions);
    if (predictions.length > 0){
      if (predictions[0].class == "squirrel"){
        fahh.play()
      }
    }


  
  
}

setInterval(function() { run(); }, 500);

